// Interface for image data
interface Image {
  src: string;
  thumbnailSrc: string;
  alt: string;
}

// Interface for tag data
interface Tag {
  label: string;
}

// Interface for bundle data
interface Bundle {
  id: string;
  name: string;
  price: string;
}

// Interface for included feature data
interface Feature {
  description: string;
}

// Interface for product data
interface Product {
  name: string;
  description: string;
  price: number;
  originalPrice: number;
  discount: number;
  images: Image[];
  tags: Tag[];
  bundles: Bundle[];
  features: Feature[];
}

// Interface for component props
interface ProductDashboardProps {
  product?: Product;
  onPurchase?: (bundle: string) => void;
  onPreview?: () => void;
}

// Default product data
