export default function ProductDetails6({
  product = defaultProduct,
  onPurchase = () => {},
  onPreview = () => {},
}: ProductDashboardProps = {}) {
  const [thumbsSwiper, setThumbsSwiper] = useState<SwiperType | null>(null);
  const [selectedBundle, setSelectedBundle] = useState<string>('starter');
  const [activeSlide, setActiveSlide] = useState<number>(0);

  const handleBundleSelect = (bundleId: string): void => {
    setSelectedBundle(bundleId);
  };

  return (
    <section className="bg-background-50 px-4 py-10 sm:p-10">
      <div className="divide-base-100 mx-auto flex max-w-[1440px] flex-col gap-10 divide-y xl:flex-row xl:divide-x xl:divide-y-0">
        {/* Image Section */}
        <div className="pb-10 xl:w-2/3 xl:pr-10 xl:pb-0">
          <div className="">
            {/* Main Slider */}
            <Swiper
              modules={[Thumbs]}
              thumbs={{ swiper: thumbsSwiper }}
              slidesPerView={1}
              onSlideChange={(swiper) => setActiveSlide(swiper.activeIndex)}
            >
              {product.images.map((image: Image, index: number) => (
                <SwiperSlide key={index}>
                  <div className="border-base-100 relative overflow-hidden rounded-xl border">
                    <img
                      src={image.src}
                      className="w-full rounded-lg"
                      alt={image.alt}
                      loading={index === 0 ? 'eager' : 'lazy'}
                    />
                    <div className="absolute top-5 right-4 flex items-center justify-center gap-2">
                      <button
                        className="text-title-50 bg-background-50 border-base-200 inline-flex h-11 w-11 cursor-pointer items-center justify-center rounded-full border"
                        aria-label="Add to wishlist"
                      >
                        <Heart />
                      </button>
                      <button
                        className="text-title-50 bg-background-50 border-base-200 inline-flex h-11 w-11 cursor-pointer items-center justify-center rounded-full border"
                        aria-label="Share product"
                      >
                        <ShareNodes />
                      </button>
                    </div>
                  </div>
                </SwiperSlide>
              ))}
            </Swiper>

            {/* Thumbnail Slider */}
            <Swiper
              modules={[Thumbs]}
              watchSlidesProgress
              onSwiper={setThumbsSwiper}
              spaceBetween={20}
              slidesPerView={4}
              className="mt-5"
            >
              {product.images.map((image: Image, index: number) => (
                <SwiperSlide key={index}>
                  <div
                    className={`ring-background-soft-400 cursor-pointer rounded-xl ring-1 transition ${
                      activeSlide === index
                        ? 'border-primary-500 border-2 ring-transparent'
                        : 'border-2 border-transparent'
                    }`}
                  >
                    <img
                      src={image.thumbnailSrc}
                      className="w-full rounded-lg"
                      alt={`Thumbnail: ${image.alt}`}
                      loading="lazy"
                    />
                  </div>
                </SwiperSlide>
              ))}
            </Swiper>
          </div>
        </div>

        {/* Product Details */}
        <div className="xl:w-1/3">
          <div className="mb-9">
            <div className="flex gap-2">
              {product.tags.map((tag: Tag, index: number) => (
                <span
                  key={index}
                  className="text-text-50 bg-background-soft-100 rounded-full px-2 py-0.5 text-xs leading-4 font-medium"
                >
                  {tag.label}
                </span>
              ))}
            </div>
            <h3 className="text-title-50 my-2 text-3xl leading-9 font-semibold">
              {product.name}
            </h3>
            <p className="text-text-100 mb-5 text-base leading-6">
              {product.description}
            </p>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-title-50 text-2xl font-bold">
                  ${product.price.toFixed(2)}
                </span>
                <span className="text-text-100 text-base font-normal -tracking-wide line-through">
                  ${product.originalPrice.toFixed(2)}
                </span>
              </div>
              <span className="text-badge-success-text bg-badge-success-background inline-block rounded-full px-2 py-0.5 text-xs leading-4 font-medium">
                Saving {product.discount}%
              </span>
            </div>
          </div>
          <div>
            <h4 className="text-title-50 mb-4 text-base font-medium">
              Choose Bundle
            </h4>
            <div className="mb-9">
              <div
                className="flex flex-col space-y-3"
                role="radiogroup"
                aria-label="Select bundle"
              >
                {product.bundles.map((bundle: Bundle) => (
                  <div
                    key={bundle.id}
                    className="flex cursor-pointer items-start gap-3"
                    onClick={() => handleBundleSelect(bundle.id)}
                    role="radio"
                    aria-checked={selectedBundle === bundle.id}
                  >
                    <RadioInput
                      size="md"
                      name="bundle"
                      checked={selectedBundle === bundle.id}
                      onChange={() => handleBundleSelect(bundle.id)}
                      className="w-fit gap-0! p-0!"
                    />
                    <div>
                      <h4 className="text-text-50 text-sm font-normal">
                        {bundle.name} {bundle.price}
                      </h4>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div className="flex flex-col gap-4 sm:flex-row">
              <Button
                onClick={() => onPurchase(selectedBundle)}
                aria-label="Purchase selected bundle"
                className="h-12 grow"
              >
                Purchase now-${product.price.toFixed(0)}
              </Button>
              <Button
                appearance="outline"
                onClick={onPreview}
                aria-label="View live preview"
                className="h-12"
              >
                <Eye />
                Live Preview
              </Button>
            </div>
            <div className="border-base-100 mt-6 flex flex-col items-center justify-center border-b pb-11">
              <div className="flex gap-4">
                <PaymentLogoOne />
                <PaymentLogoFive />
                <PaymentLogoTwo />
                <PaymentLogoThree />
                <PaymentLogoFour />
              </div>
              <div className="mt-3 flex justify-center gap-1 text-center sm:flex-row sm:text-left">
                <p className="text-text-100 inline justify-center text-center text-base -tracking-tight">
                  <Shield1Check className="inline" />
                  <span>Secure checkout with encrypted payment processing</span>
                </p>
              </div>
            </div>
            <div className="mt-11">
              <h4 className="text-title-50 mb-3 text-base font-medium">
                What’s included
              </h4>
              <ul className="list-inside list-disc space-y-1">
                {product.features.map((feature: Feature, index: number) => (
                  <li key={index} className="text-text-100 text-base">
                    {feature.description}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
